#!/usr/bin/env python3

import os
import sys
import subprocess
import json
import glob

class CLIRunner:
    def __init__(self):
        """Initialize CLI runner"""
        self.script_dir = os.path.dirname(os.path.abspath(__file__))
        self.upload_dir = os.path.join(self.script_dir, "uploads")
        if not os.path.exists(self.upload_dir):
            os.makedirs(self.upload_dir)
        self.config_file = "cli_runner_config.json"

    def list_scripts(self):
        """List available scripts"""
        print("Available scripts:")
        print("-" * 50)

        # Find Python scripts
        scripts = []
        for root, dirs, files in os.walk(self.script_dir):
            # Skip __pycache__ and uploads directories
            dirs[:] = [d for d in dirs if d not in ['__pycache__', 'uploads']]

            for file in files:
                if file.endswith('.py') and file not in ['cli_runner.py', 'script_ui.py', 'script_runner.py']:
                    script_path = os.path.join(root, file)
                    scripts.append(script_path)

        # Sort scripts by name
        scripts.sort(key=lambda x: os.path.basename(x))

        # Display scripts
        for i, script in enumerate(scripts, 1):
            rel_path = os.path.relpath(script, self.script_dir)
            print(f"{i}. {rel_path}")

        print("-" * 50)
        return scripts

    def list_attachments(self):
        """List available attachments"""
        attachments = []
        if os.path.exists(self.upload_dir):
            for file in os.listdir(self.upload_dir):
                if os.path.isfile(os.path.join(self.upload_dir, file)):
                    attachments.append(os.path.join(self.upload_dir, file))

        if attachments:
            print("Available attachments:")
            print("-" * 50)
            for i, attachment in enumerate(attachments, 1):
                rel_path = os.path.relpath(attachment, self.script_dir)
                print(f"{i}. {rel_path}")
            print("-" * 50)
        else:
            print("No attachments available.")

        return attachments

    def detect_script_parameters(self, script_path):
        """Detect script parameters"""
        parameters = []

        try:
            with open(script_path, 'r', encoding='utf-8') as f:
                content = f.read()

            # Look for sys.argv usage
            if 'sys.argv' in content:
                import re
                # Look for len(sys.argv) checks
                len_checks = re.findall(r'len\(sys\.argv\)\s*([<>=!]+)\s*(\d+)', content)
                if len_checks:
                    operator, num_str = len_checks[0]
                    required_args = int(num_str) - 1
                    if required_args > 0:
                        parameters.extend([f"Arg {i}" for i in range(1, required_args + 1)])

            # Look for argparse usage
            if 'argparse' in content:
                import re
                args = re.findall(r'add_argument\([\'\"]([^\"\']+)[\'\"]', content)
                if args:
                    parameters.extend([f"--{arg}" for arg in args])

        except Exception as e:
            print(f"Error detecting parameters: {e}")

        return parameters

    def run_script(self, script_path, params=None):
        """Run script with parameters"""
        if not os.path.exists(script_path):
            print(f"Error: Script {script_path} does not exist.")
            return

        # Prepare command
        cmd = [sys.executable, script_path]

        # Add parameters
        if params:
            cmd.extend(params)

        print(f"\nRunning: {' '.join(cmd)}")
        print(f"Work directory: {self.script_dir}")
        print("-" * 50)

        # Run script
        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                cwd=self.script_dir
            )

            # Print output
            if result.stdout:
                print("Output:")
                print(result.stdout)

            # Print errors
            if result.stderr:
                print("Errors:")
                print(result.stderr)

            print(f"\nExit code: {result.returncode}")
            if result.returncode == 0:
                print("Script completed successfully!")
            else:
                print("Script failed.")

        except Exception as e:
            print(f"Error running script: {e}")

    def main(self):
        """Main function"""
        print("Script Runner CLI")
        print("=" * 50)

        # List scripts
        scripts = self.list_scripts()

        if not scripts:
            print("No scripts found.")
            return

        # Select script
        while True:
            try:
                choice = int(input("\nEnter script number to run (0 to exit): "))
                if choice == 0:
                    print("Exiting...")
                    return
                elif 1 <= choice <= len(scripts):
                    selected_script = scripts[choice - 1]
                    break
                else:
                    print("Invalid choice. Please try again.")
            except ValueError:
                print("Please enter a number.")

        print(f"\nSelected script: {os.path.basename(selected_script)}")

        # Detect parameters
        parameters = self.detect_script_parameters(selected_script)

        # List attachments
        attachments = self.list_attachments()

        # Get parameters from user
        user_params = []

        if parameters:
            print("\nParameters:")
            print("-" * 50)

            for param in parameters:
                if param.startswith('Arg'):
                    # For positional arguments, suggest attachments
                    if attachments:
                        print(f"\nAvailable attachments for {param}:")
                        for i, att in enumerate(attachments, 1):
                            print(f"  {i}. {os.path.basename(att)}")
                        print("  0. Enter custom value")

                        try:
                            att_choice = int(input(f"Select attachment for {param} (0 for custom): "))
                            if att_choice == 0:
                                value = input(f"Enter value for {param}: ")
                            elif 1 <= att_choice <= len(attachments):
                                value = attachments[att_choice - 1]
                            else:
                                value = input(f"Enter value for {param}: ")
                        except ValueError:
                            value = input(f"Enter value for {param}: ")
                    else:
                        value = input(f"Enter value for {param}: ")
                    user_params.append(value)
                else:
                    # For named arguments
                    value = input(f"Enter value for {param}: ")
                    user_params.extend([param, value])

        # Run script
        self.run_script(selected_script, user_params)

        # Ask to run another script
        while True:
            again = input("\nRun another script? (y/n): ").lower()
            if again == 'y':
                self.main()
                return
            elif again == 'n':
                print("Exiting...")
                return
            else:
                print("Please enter 'y' or 'n'.")

if __name__ == "__main__":
    runner = CLIRunner()
    runner.main()

#!/usr/bin/env python3

import os
import sys
import subprocess
import json
import shutil

class ScriptRunner:
    def __init__(self):
        """Initialize script runner"""
        self.base_dir = os.path.dirname(os.path.abspath(__file__))
        self.upload_dir = os.path.join(self.base_dir, "uploads")
        if not os.path.exists(self.upload_dir):
            os.makedirs(self.upload_dir)
        self.config_file = os.path.join(self.base_dir, "run_script_config.json")

    def list_scripts(self):
        """List available scripts"""
        print("Available scripts:")
        print("-" * 60)

        scripts = []
        script_extensions = ['.py', '.sh']

        # Search for scripts in current directory and subdirectories
        for root, dirs, files in os.walk(self.base_dir):
            # Skip certain directories
            dirs[:] = [d for d in dirs if d not in ['__pycache__', 'uploads']]

            for file in files:
                if any(file.endswith(ext) for ext in script_extensions):
                    # Skip this script itself
                    if file == os.path.basename(__file__):
                        continue
                    script_path = os.path.join(root, file)
                    scripts.append(script_path)

        # Also check /mnt/d/script directory
        script_dir = "/mnt/d/script"
        if os.path.exists(script_dir):
            for file in os.listdir(script_dir):
                if any(file.endswith(ext) for ext in script_extensions):
                    script_path = os.path.join(script_dir, file)
                    scripts.append(script_path)

        # Sort and display scripts
        scripts.sort(key=lambda x: os.path.basename(x))

        for i, script in enumerate(scripts, 1):
            rel_path = os.path.relpath(script, self.base_dir)
            print(f"{i:2d}. {rel_path}")

        print("-" * 60)
        return scripts

    def list_attachments(self):
        """List available attachments"""
        attachments = []

        if os.path.exists(self.upload_dir):
            for file in os.listdir(self.upload_dir):
                file_path = os.path.join(self.upload_dir, file)
                if os.path.isfile(file_path):
                    attachments.append(file_path)

        if attachments:
            print("Available attachments:")
            print("-" * 60)
            for i, attachment in enumerate(attachments, 1):
                size = os.path.getsize(attachment)
                size_str = f"{size:,} bytes"
                print(f"{i:2d}. {os.path.basename(attachment)} ({size_str})")
            print("-" * 60)
        else:
            print("No attachments available.")

        return attachments

    def detect_parameters(self, script_path):
        """Detect script parameters"""
        parameters = []

        try:
            with open(script_path, 'r', encoding='utf-8', errors='ignore') as f:
                content = f.read()

            # Detect Python script parameters
            if script_path.endswith('.py'):
                # Look for argparse
                if 'argparse' in content:
                    import re
                    args = re.findall(r'add_argument\([\'"]([^"\']+)[\'"]', content)
                    if args:
                        parameters.extend([f"--{arg}" for arg in args])

                # Look for sys.argv
                elif 'sys.argv' in content:
                    import re
                    len_checks = re.findall(r'len\(sys\.argv\)\s*([<>=!]+)\s*(\d+)', content)
                    if len_checks:
                        required_args = int(len_checks[0][1]) - 1
                        if required_args > 0:
                            parameters.extend([f"Arg {i}" for i in range(1, required_args + 1)])

            # Detect Shell script parameters
            elif script_path.endswith('.sh'):
                if 'getopts' in content:
                    import re
                    opts = re.findall(r'getopts\s+([a-zA-Z]+)', content)
                    if opts:
                        for opt_string in opts:
                            for opt in opt_string:
                                parameters.append(f"-{opt}")

        except Exception as e:
            print(f"Warning: Error detecting parameters: {e}")

        return parameters

    def upload_file(self, file_path):
        """Upload file to attachments directory"""
        if not os.path.exists(file_path):
            print(f"Error: File not found: {file_path}")
            return False

        try:
            dest_path = os.path.join(self.upload_dir, os.path.basename(file_path))
            shutil.copy2(file_path, dest_path)
            print(f"Uploaded: {os.path.basename(file_path)} -> {os.path.basename(dest_path)}")
            return True
        except Exception as e:
            print(f"Error uploading file: {e}")
            return False

    def run_script(self, script_path, parameters):
        """Run script with given parameters"""
        if not os.path.exists(script_path):
            print(f"Error: Script not found: {script_path}")
            return

        print(f"\nRunning: {os.path.basename(script_path)}")
        print("-" * 60)

        # Prepare command
        if script_path.endswith('.py'):
            cmd = [sys.executable, script_path]
        else:
            cmd = [script_path]

        # Add parameters
        cmd.extend(parameters)

        print(f"Command: {' '.join(cmd)}")
        print(f"Working directory: {self.base_dir}")
        print("-" * 60)

        # Run script
        try:
            process = subprocess.Popen(
                cmd,
                cwd=self.base_dir,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                text=True,
                bufsize=1
            )

            # Read output
            for line in iter(process.stdout.readline, ''):
                print(line, end='')

            process.stdout.close()
            returncode = process.wait()

            print("-" * 60)
            print(f"Exit code: {returncode}")

            if returncode == 0:
                print("✓ Script completed successfully!")
            else:
                print("✗ Script failed with error code:", returncode)

        except KeyboardInterrupt:
            print("\n✗ Script interrupted by user")
            return
        except Exception as e:
            print(f"✗ Error running script: {e}")

    def main(self):
        """Main function"""
        print("Script Runner CLI")
        print("=" * 60)
        print("A command-line tool to run scripts without GUI")
        print("=" * 60)

        while True:
            print("\nOptions:")
            print("1. List available scripts")
            print("2. List attachments")
            print("3. Upload file")
            print("4. Run script")
            print("5. Exit")

            choice = input("\nEnter your choice (1-5): ")

            if choice == '1':
                self.list_scripts()

            elif choice == '2':
                self.list_attachments()

            elif choice == '3':
                file_path = input("Enter file path to upload: ")
                if file_path:
                    self.upload_file(file_path)

            elif choice == '4':
                # List scripts
                scripts = self.list_scripts()

                if not scripts:
                    print("No scripts found.")
                    continue

                # Select script
                while True:
                    try:
                        script_num = int(input("\nEnter script number: "))
                        if 1 <= script_num <= len(scripts):
                            selected_script = scripts[script_num - 1]
                            break
                        else:
                            print(f"Please enter a number between 1 and {len(scripts)}")
                    except ValueError:
                        print("Please enter a valid number")

                print(f"\nSelected: {os.path.basename(selected_script)}")

                # Detect parameters
                parameters = self.detect_parameters(selected_script)

                # Get user input for parameters
                user_params = []

                if parameters:
                    print("\nParameters detected:")
                    print("-" * 60)

                    for param in parameters:
                        if param.startswith('Arg'):
                            # For positional arguments
                            value = input(f"Enter value for {param}: ")
                            if value:
                                user_params.append(value)
                        else:
                            # For named arguments
                            value = input(f"Enter value for {param}: ")
                            if value:
                                user_params.append(param)
                                user_params.append(value)
                else:
                    # No parameters detected, ask for any arguments
                    args = input("Enter any additional arguments (space-separated): ")
                    if args:
                        user_params.extend(args.split())

                # Run script
                self.run_script(selected_script, user_params)

            elif choice == '5':
                print("Exiting...")
                break

            else:
                print("Invalid choice. Please try again.")

if __name__ == "__main__":
    runner = ScriptRunner()
    runner.main()

#!/usr/bin/env python3
# -*- coding: utf-8 -*-

import sys, json, os
from anarci import anarci
from Bio import SeqIO
from docx import Document
from docx.shared import RGBColor

# CDR 定义（IMGT）
CDR_DEFS = {
    "CDR1": range(27, 39),
    "CDR2": range(56, 66),
    "CDR3": range(105, 118),
}

# 终端颜色
ANSI = {
    "CDR1": "\033[31m",
    "CDR2": "\033[32m",
    "CDR3": "\033[34m",
    "RESET": "\033[0m"
}

# Word 颜色
CDR_COLORS = {
    "CDR1": RGBColor(255, 0, 0),
    "CDR2": RGBColor(0, 128, 0),
    "CDR3": RGBColor(0, 0, 255)
}

# ----------------------------
def map_cdrs_to_original(numbering_list, original_seq):
    # numbering_list: [( (number, ins), aa ), ...]
    map_align_to_orig = []
    orig_counter = 0
    for pos, aa in numbering_list:
        if aa == '-' or aa is None:
            map_align_to_orig.append(None)
        else:
            orig_counter += 1
            map_align_to_orig.append(orig_counter)

    cdrs = {}
    for name, imgt_range in CDR_DEFS.items():
        aa_list = []
        start_orig = None
        end_orig = None
        for i, (pos, aa) in enumerate(numbering_list):
            if pos is None or aa in (None,'-'):
                continue
            num, ins = pos
            if num in imgt_range:
                mapped = map_align_to_orig[i]
                if mapped is not None:
                    if start_orig is None:
                        start_orig = mapped
                    end_orig = mapped
                    aa_list.append(aa)
        cdrs[name] = {"seq": "".join(aa_list), "start": start_orig, "end": end_orig} if aa_list else {"seq": "", "start": None, "end": None}
    return cdrs

def colorize_sequence(original_seq, cdr_info):
    n = len(original_seq)
    tag_map = [None]*n
    for name in ("CDR1","CDR2","CDR3"):
        info = cdr_info.get(name,{})
        s = info.get("start")
        e = info.get("end")
        if s and e:
            for i in range(s-1, e):
                if 0 <= i < n:
                    tag_map[i] = name
    # 终端彩色序列
    colored_chars = []
    current_tag = None
    for i, aa in enumerate(original_seq):
        tag = tag_map[i]
        if tag != current_tag:
            if current_tag is not None:
                colored_chars.append(ANSI["RESET"])
            if tag is not None:
                colored_chars.append(ANSI[tag])
            current_tag = tag
        colored_chars.append(aa)
    if current_tag is not None:
        colored_chars.append(ANSI["RESET"])
    colored_seq = "".join(colored_chars)

    # 带标签的序列
    tagged_chars = []
    current_tag = None
    for i, aa in enumerate(original_seq):
        tag = tag_map[i]
        if tag != current_tag:
            if current_tag is not None:
                tagged_chars.append(f"[/{current_tag}]")
            if tag is not None:
                tagged_chars.append(f"[{tag}:{i+1}]")
            current_tag = tag
        tagged_chars.append(aa)
    if current_tag is not None:
        tagged_chars.append(f"[/{current_tag}]")
    tagged_seq = "".join(tagged_chars)
    return colored_seq, tagged_seq

def write_word(fasta_file, cdr_data, output_docx):
    doc = Document()
    for rec in SeqIO.parse(fasta_file, "fasta"):
        seq_id = rec.id
        seq = str(rec.seq)
        doc.add_paragraph(f">{seq_id}", style='Intense Quote')
        p = doc.add_paragraph()
        cdr_info = cdr_data.get(seq_id, {}).get("CDRs",{})
        for i, aa in enumerate(seq):
            run = p.add_run(aa)
            color_set = False
            for cdr_name in ("CDR1","CDR2","CDR3"):
                info = cdr_info.get(cdr_name,{})
                s = info.get("start")
                e = info.get("end")
                if s and e and (s-1) <= i <= (e-1):
                    run.font.color.rgb = CDR_COLORS[cdr_name]
                    color_set = True
                    break
            if not color_set:
                run.font.color.rgb = RGBColor(0,0,0)
    doc.save(output_docx)
    print(f"Word 文件生成: {output_docx}", file=sys.stderr)

def process_fasta(fasta_file):
    results = {}
    base = os.path.splitext(os.path.basename(fasta_file))[0]
    colored_fname = f"{base}_colored.fasta"
    tagged_fname = f"{base}_tagged.fasta"
    word_fname = f"{base}_colored.docx"

    with open(colored_fname,"w",encoding="utf-8") as cf, open(tagged_fname,"w",encoding="utf-8") as tf:
        for rec in SeqIO.parse(fasta_file,"fasta"):
            seq = str(rec.seq).strip()
            if not seq:
                continue
            try:
                res = anarci([("seq", seq)], scheme="imgt")
            except Exception as e:
                print(f"ANARCI 识别失败: {e}", file=sys.stderr)
                results[rec.id] = {}
                continue
            try:
                numbering_list = res[0][0][0][0]  # [( (num, ins), aa ), ...]
                chain_type = res[1][0][0].get("chain_type","") if res[1] and res[1][0] else ""
            except Exception as e:
                print(f"解析 ANARCI 返回值失败: {e}", file=sys.stderr)
                results[rec.id] = {}
                continue

            cdr_info = map_cdrs_to_original(numbering_list, seq)
            results[rec.id] = {"chain_type": chain_type, "sequence_length": len(seq), "CDRs": cdr_info}

            colored_seq, tagged_seq = colorize_sequence(seq, cdr_info)
            # 彩色FASTA
            cf.write(f">{rec.id} colored\n")
            for i in range(0,len(colored_seq),60):
                cf.write(colored_seq[i:i+60]+"\n")
            # 标签FASTA
            tf.write(f">{rec.id} tagged\n")
            for i in range(0,len(tagged_seq),60):
                tf.write(tagged_seq[i:i+60]+"\n")

    write_word(fasta_file, results, word_fname)
    return results, colored_fname, tagged_fname, word_fname

def main():
    if len(sys.argv)<2:
        print("用法: python3 fab_cdr_export.py input.fasta > output.json")
        sys.exit(1)
    fasta_file = sys.argv[1]
    results, colored_file, tagged_file, word_file = process_fasta(fasta_file)
    print(json.dumps(results, ensure_ascii=False, indent=2))
    print(f"彩色FASTA: {colored_file}", file=sys.stderr)
    print(f"带标签FASTA: {tagged_file}", file=sys.stderr)
    print(f"Word文件: {word_file}", file=sys.stderr)

if __name__=="__main__":
    main()

#!/usr/bin/env python3

import os
import sys
import subprocess

class SegIDRunner:
    def __init__(self):
        """Initialize SegID runner"""
        self.base_dir = os.path.dirname(os.path.abspath(__file__))
        self.segid_path = "/mnt/d/script/segID.py"
        self.upload_dir = os.path.join(self.base_dir, "uploads")

        if not os.path.exists(self.upload_dir):
            os.makedirs(self.upload_dir)

    def check_segid(self):
        """Check if segID.py exists"""
        if not os.path.exists(self.segid_path):
            print(f"Error: segID.py not found at {self.segid_path}")
            return False
        return True

    def list_pdb_files(self):
        """List available PDB files"""
        pdb_files = []

        # Check current directory
        for file in os.listdir(self.base_dir):
            if file.endswith('.pdb'):
                pdb_files.append(os.path.join(self.base_dir, file))

        # Check uploads directory
        if os.path.exists(self.upload_dir):
            for file in os.listdir(self.upload_dir):
                if file.endswith('.pdb'):
                    pdb_files.append(os.path.join(self.upload_dir, file))

        if pdb_files:
            print("Available PDB files:")
            print("-" * 60)
            for i, pdb_file in enumerate(pdb_files, 1):
                size = os.path.getsize(pdb_file)
                rel_path = os.path.relpath(pdb_file, self.base_dir)
                print(f"{i:2d}. {rel_path} ({size:,} bytes)")
            print("-" * 60)
        else:
            print("No PDB files found in current directory or uploads/")

        return pdb_files

    def run_segid(self, input_pdb, output_pdb):
        """Run segID.py on the given PDB file"""
        if not self.check_segid():
            return

        if not os.path.exists(input_pdb):
            print(f"Error: Input PDB file not found: {input_pdb}")
            return

        print(f"\nRunning segID.py")
        print("-" * 60)
        print(f"Input:  {os.path.relpath(input_pdb, self.base_dir)}")
        print(f"Output: {os.path.relpath(output_pdb, self.base_dir)}")
        print("-" * 60)

        # Run segID.py
        try:
            cmd = [sys.executable, self.segid_path, input_pdb, output_pdb]

            result = subprocess.run(
                cmd,
                cwd=self.base_dir,
                capture_output=True,
                text=True
            )

            # Print output
            if result.stdout:
                print("Output:")
                print(result.stdout)

            # Print errors
            if result.stderr:
                print("Errors:")
                print(result.stderr)

            print("-" * 60)
            print(f"Exit code: {result.returncode}")

            if result.returncode == 0:
                print("✓ segID.py completed successfully!")
                print(f"Output file: {os.path.relpath(output_pdb, self.base_dir)}")
            else:
                print("✗ segID.py failed!")

        except Exception as e:
            print(f"✗ Error running segID.py: {e}")

    def main(self):
        """Main function"""
        print("segID.py Runner")
        print("=" * 60)
        print("A tool to run segID.py without GUI")
        print("=" * 60)

        if not self.check_segid():
            return

        # List PDB files
        pdb_files = self.list_pdb_files()

        # Get input file
        if pdb_files:
            while True:
                try:
                    choice = int(input("\nEnter PDB file number to process (0 to enter path): "))
                    if choice == 0:
                        input_pdb = input("Enter input PDB file path: ")
                        break
                    elif 1 <= choice <= len(pdb_files):
                        input_pdb = pdb_files[choice - 1]
                        break
                    else:
                        print(f"Please enter a number between 0 and {len(pdb_files)}")
                except ValueError:
                    print("Please enter a valid number")
        else:
            input_pdb = input("Enter input PDB file path: ")

        # Get output file
        if input_pdb:
            base_name = os.path.splitext(os.path.basename(input_pdb))[0]
            default_output = os.path.join(self.base_dir, f"{base_name}_clean.pdb")
            output_pdb = input(f"Enter output PDB file path [{os.path.basename(default_output)}]: ")

            if not output_pdb:
                output_pdb = default_output

        # Run segID.py
        if input_pdb and output_pdb:
            self.run_segid(input_pdb, output_pdb)

if __name__ == "__main__":
    runner = SegIDRunner()
    runner.main()
